87	            if (space.isString()) {
88	                const str = try space.toBunString(global);
89	                if (str.length() == 0) {
90	                    str.deref();
91	                    return .minified;
92	                }
93	                return .{ .str = str };
94	            }
95	
96	            return .minified;
97	        }
