857	                            },
858	                            'o', 'O' => {
859	                                base = .oct;
860	                            },
861	                            '0'...'9' => {
862	                                // 0 prefix allowed
863	                            },
864	                            else => {
865	                                offset.* = i;
866	                                return false;
867	                            },
868	                        }
869	                        i += 1;
870	                    } else {
