        const str = "value: 42";
        const encoder = new TextEncoder();
        const bytes = encoder.encode(str);
        // Ensure buffer is aligned for Int32Array
        const alignedBuffer = new ArrayBuffer(Math.ceil(bytes.length / 4) * 4);
