const std = @import("std");
const bun = @import("bun");
const strings = bun.strings;
const jsc = bun.jsc;
const JSValue = jsc.JSValue;
const JSGlobalObject = jsc.JSGlobalObject;
const ZigString = jsc.ZigString;
const JSError = bun.JSError;
const string = bun.string;

pub const INI = struct {
    /// Parse an INI string and return a JSValue representing the parsed object.
    /// Supports:
    /// - [section] headers (creating nested objects)
    /// - key=value and key: value pairs
    /// - Comment lines starting with ; or #
    /// - Quoted string values (single and double quotes)
    /// - Inline comments
    /// - Multi-level section nesting with dots: [a.b.c]
    /// - Empty values (key without value becomes empty string)
    pub fn parse(globalThis: *JSGlobalObject, input: []const u8) JSError!JSValue {
        const root = JSValue.createEmptyObject(globalThis, 0);
        var current_section = root;

        var line_iter = LineIterator.init(input);

        while (line_iter.next()) |raw_line| {
            const line = trimLine(raw_line);

            // Skip empty lines and comments
            if (line.len == 0) continue;
            if (line[0] == ';' or line[0] == '#') continue;

            // Section header
            if (line[0] == '[') {
                current_section = try parseSectionHeader(globalThis, root, line);
                continue;
            }

            // Key-value pair
            try parseKeyValue(globalThis, current_section, line);
        }

        return root;
    }

    /// Stringify a JSValue into INI format string.
    pub fn stringify(globalThis: *JSGlobalObject, value: JSValue) JSError!JSValue {
        if (!value.isObject()) {
            return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
        }

        var buf = std.ArrayList(u8).init(bun.default_allocator);
        defer buf.deinit();

        try stringifyObject(globalThis, value, &buf, null);

        var out = bun.String.createUTF8(buf.items);
        defer out.deref();
        return out.toJS(globalThis);
    }

    fn stringifyObject(globalThis: *JSGlobalObject, value: JSValue, buf: *std.ArrayList(u8), section_prefix: ?[]const u8) JSError!void {
        // Two passes: first scalar properties, then nested objects (sections)
        var iter = try JSValue.JSObjectIterator.init(value, globalThis);
        defer iter.deinit();

        // First pass: write scalar key=value pairs
        while (iter.next()) |entry| {
            const val = entry.value;
            if (val.isObject() and !val.isNull() and !val.isArray()) {
                continue; // Handle nested objects in second pass
            }
            const key = entry.key;
            const key_slice = key.toUTF8(bun.default_allocator);
            defer key_slice.deinit();
            try buf.appendSlice(key_slice.slice());
            try buf.append('=');
            try appendValue(globalThis, val, buf);
            try buf.append('\n');
        }

        // Second pass: write nested objects as sections
        var iter2 = try JSValue.JSObjectIterator.init(value, globalThis);
        defer iter2.deinit();

        while (iter2.next()) |entry| {
            const val = entry.value;
            if (!val.isObject() or val.isNull() or val.isArray()) {
                continue;
            }
            const key = entry.key;
            const key_slice = key.toUTF8(bun.default_allocator);
            defer key_slice.deinit();

            // Build section name
            var section_name = std.ArrayList(u8).init(bun.default_allocator);
            defer section_name.deinit();

            if (section_prefix) |prefix| {
                try section_name.appendSlice(prefix);
                try section_name.append('.');
            }
            try section_name.appendSlice(key_slice.slice());

            // Add blank line before section for readability
            if (buf.items.len > 0 and buf.items[buf.items.len - 1] != '\n') {
                try buf.append('\n');
            }
            if (buf.items.len > 0) {
                try buf.append('\n');
            }

            try buf.append('[');
            try buf.appendSlice(section_name.items);
            try buf.append(']');
            try buf.append('\n');

            try stringifyObject(globalThis, val, buf, section_name.items);
        }
    }

    fn appendValue(globalThis: *JSGlobalObject, value: JSValue, buf: *std.ArrayList(u8)) JSError!void {
        if (value.isNull() or value.isUndefined()) {
            // Write nothing (empty value)
            return;
        }
        if (value.isBoolean()) {
            if (value.toBoolean()) {
                try buf.appendSlice("true");
            } else {
                try buf.appendSlice("false");
            }
            return;
        }
        if (value.isNumber()) {
            const num = value.coerceToDouble(globalThis);
            var num_buf: [64]u8 = undefined;
            const num_str = std.fmt.bufPrint(&num_buf, "{d}", .{num}) catch return;
            try buf.appendSlice(num_str);
            return;
        }
        if (value.isString()) {
            const str = try value.toSlice(globalThis, bun.default_allocator);
            defer str.deinit();
            try buf.appendSlice(str.slice());
            return;
        }
        if (value.isArray()) {
            // Represent arrays as comma-separated values
            const len = value.getLength(globalThis);
            var i: u32 = 0;
            while (i < len) : (i += 1) {
                if (i > 0) try buf.appendSlice(", ");
                const item = value.getIndex(globalThis, i);
                try appendValue(globalThis, item, buf);
            }
            return;
        }
        // Fallback: convert to string
        const str = try value.toSlice(globalThis, bun.default_allocator);
        defer str.deinit();
        try buf.appendSlice(str.slice());
    }

    fn parseSectionHeader(globalThis: *JSGlobalObject, root: JSValue, line: []const u8) JSError!JSValue {
        // Find closing bracket
        const close = strings.indexOfChar(line, ']') orelse return root;
        if (close <= 1) return root;

        const section_name = trimLine(line[1..close]);
        if (section_name.len == 0) return root;

        // Support dotted sections like [a.b.c]
        var current = root;
        var name_iter = DotIterator.init(section_name);
        while (name_iter.next()) |part| {
            const trimmed = trimLine(part);
            if (trimmed.len == 0) continue;

            var key = ZigString.init(trimmed);
            const existing = current.getWithZigString(globalThis, &key);
            if (existing.isUndefined() or existing.isNull() or !existing.isObject()) {
                const new_obj = JSValue.createEmptyObject(globalThis, 0);
                current.putWithZigString(globalThis, &key, new_obj);
                current = new_obj;
            } else {
                current = existing;
            }
        }

        return current;
    }

    fn parseKeyValue(globalThis: *JSGlobalObject, section: JSValue, line: []const u8) JSError!void {
        // Find separator (= or :)
        var sep_idx: ?usize = null;
        for (line, 0..) |c, i| {
            if (c == '=' or c == ':') {
                sep_idx = i;
                break;
            }
        }

        const key_end = sep_idx orelse line.len;
        const key = trimLine(line[0..key_end]);
        if (key.len == 0) return;

        const raw_value = if (sep_idx) |idx|
            (if (idx + 1 < line.len) trimLine(line[idx + 1 ..]) else "")
        else
            "";

        // Strip inline comments (not inside quotes)
        const value_str = stripInlineComment(raw_value);

        // Parse the value
        const js_value = parseValue(globalThis, value_str);

        var zig_key = ZigString.init(key);
        section.putWithZigString(globalThis, &zig_key, js_value);
    }

    fn parseValue(globalThis: *JSGlobalObject, value: []const u8) JSValue {
        if (value.len == 0) return bun.String.empty.toJS(globalThis);

        // Handle quoted strings
        if (value.len >= 2) {
            if ((value[0] == '"' and value[value.len - 1] == '"') or
                (value[0] == '\'' and value[value.len - 1] == '\''))
            {
                const inner = value[1 .. value.len - 1];
                var s = bun.String.createUTF8(inner);
                defer s.deref();
                return s.toJS(globalThis);
            }
        }

        // Handle boolean values
        if (strings.eqlComptime(value, "true") or strings.eqlComptime(value, "yes") or strings.eqlComptime(value, "on")) {
            return JSValue.true;
        }
        if (strings.eqlComptime(value, "false") or strings.eqlComptime(value, "no") or strings.eqlComptime(value, "off")) {
            return JSValue.false;
        }

        // Handle null
        if (strings.eqlComptime(value, "null") or strings.eqlComptime(value, "none")) {
            return JSValue.null;
        }

        // Try to parse as integer
        if (std.fmt.parseInt(i64, value, 10)) |int_val| {
            return JSValue.jsNumber(int_val);
        } else |_| {}

        // Try to parse as float
        if (std.fmt.parseFloat(f64, value)) |float_val| {
            return JSValue.jsNumber(float_val);
        } else |_| {}

        // Return as string
        var s = bun.String.createUTF8(value);
        defer s.deref();
        return s.toJS(globalThis);
    }

    fn stripInlineComment(value: []const u8) []const u8 {
        var in_single_quote = false;
        var in_double_quote = false;

        for (value, 0..) |c, i| {
            if (c == '\'' and !in_double_quote) {
                in_single_quote = !in_single_quote;
            } else if (c == '"' and !in_single_quote) {
                in_double_quote = !in_double_quote;
            } else if ((c == ';' or c == '#') and !in_single_quote and !in_double_quote) {
                return trimLine(value[0..i]);
            }
        }
        return value;
    }

    fn trimLine(s: []const u8) []const u8 {
        return strings.trim(s, " \t\r");
    }

    const LineIterator = struct {
        data: []const u8,
        pos: usize,

        fn init(data: []const u8) LineIterator {
            return .{ .data = data, .pos = 0 };
        }

        fn next(self: *LineIterator) ?[]const u8 {
            if (self.pos >= self.data.len) return null;

            const start = self.pos;
            while (self.pos < self.data.len and self.data[self.pos] != '\n') {
                self.pos += 1;
            }
            const end = self.pos;
            // Skip the newline
            if (self.pos < self.data.len) self.pos += 1;

            return self.data[start..end];
        }
    };

    const DotIterator = struct {
        data: []const u8,
        pos: usize,

        fn init(data: []const u8) DotIterator {
            return .{ .data = data, .pos = 0 };
        }

        fn next(self: *DotIterator) ?[]const u8 {
            if (self.pos >= self.data.len) return null;

            const start = self.pos;
            while (self.pos < self.data.len and self.data[self.pos] != '.') {
                self.pos += 1;
            }
            const end = self.pos;
            // Skip the dot
            if (self.pos < self.data.len) self.pos += 1;

            return self.data[start..end];
        }
    };
};

