      const result = Bun.INI.parse(`
[section]
key=value
name=hello
`);
      expect(result).toEqual({
        section: {
          key: "value",
          name: "hello",
        },
      });
    });

    test("multiple sections", () => {
      const result = Bun.INI.parse(`
top=1

[section1]
a=1

[section2]
b=2
`);
      expect(result).toEqual({
        top: 1,
        section1: { a: 1 },
        section2: { b: 2 },
      });
    });

    test("dotted section names create deeply nested objects", () => {
      const result = Bun.INI.parse(`
[a.b.c]
key=value
`);
      expect(result).toEqual({
        a: { b: { c: { key: "value" } } },
      });
    });

    test("semicolon comments are ignored", () => {
      const result = Bun.INI.parse(`
; This is a comment
key=value
; Another comment
`);
      expect(result).toEqual({ key: "value" });
    });

    test("hash comments are ignored", () => {
      const result = Bun.INI.parse(`
# This is a comment
key=value
# Another comment
`);
      expect(result).toEqual({ key: "value" });
    });

    test("inline comments are stripped", () => {
      const result = Bun.INI.parse("key=value ; this is a comment\nname=hello # another comment");
      expect(result).toEqual({ key: "value", name: "hello" });
    });

    test("inline comments inside quotes are preserved", () => {
      const result = Bun.INI.parse(`key="value ; not a comment"`);
      expect(result).toEqual({ key: "value ; not a comment" });
    });

    test("quoted values (double quotes)", () => {
      const result = Bun.INI.parse(`key="hello world"`);
      expect(result).toEqual({ key: "hello world" });
    });

    test("quoted values (single quotes)", () => {
