      expect(result).toEqual({ key: "hello world" });
    });

    test("boolean values", () => {
      const result = Bun.INI.parse(`
a=true
b=false
c=yes
d=no
e=on
f=off
`);
      expect(result).toEqual({
        a: true,
        b: false,
        c: true,
        d: false,
        e: true,
        f: false,
      });
