      const result = Bun.INI.stringify({ a: true, b: false });
      expect(result).toContain("a=true");
      expect(result).toContain("b=false");
    });

    test("number values", () => {
      const result = Bun.INI.stringify({ count: 42, pi: 3.14 });
      expect(result).toContain("count=42");
    });

    test("null/undefined values produce empty values", () => {
      const result = Bun.INI.stringify({ key: null });
      expect(result).toContain("key=");
    });

    test("deeply nested objects use dotted section names", () => {
      const result = Bun.INI.stringify({
        a: { b: { key: "value" } },
      });
      expect(result).toContain("[a.b]");
      expect(result).toContain("key=value");
    });

    test("mixed scalar and nested", () => {
      const result = Bun.INI.stringify({
        global: "yes",
        section: { inner: "val" },
      });
      expect(result).toContain("global=yes");
      expect(result).toContain("[section]");
      expect(result).toContain("inner=val");
    });

    test("throws on non-object input", () => {
      // @ts-expect-error
      expect(() => Bun.INI.stringify("not an object")).toThrow();
    });

    test("roundtrip: parse(stringify(obj)) preserves structure", () => {
