        global_key: "global_value",
        database: {
          host: "localhost",
          port: 5432,
        },
      };
      const ini = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(ini);
      expect(parsed).toEqual(original);
    });
  });
});

