1	const std = @import("std");
2	const bun = @import("bun");
3	const strings = bun.strings;
4	const jsc = bun.jsc;
5	const JSValue = jsc.JSValue;
6	const JSGlobalObject = jsc.JSGlobalObject;
7	const ZigString = jsc.ZigString;
8	const JSError = bun.JSError;
9	
10	pub const INI = struct {
11	    /// Parse an INI string and return a JSValue representing the parsed object.
12	    /// Supports:
13	    /// - [section] headers (creating nested objects)
14	    /// - key=value and key: value pairs
15	    /// - Comment lines starting with ; or #
16	    /// - Quoted string values (single and double quotes)
17	    /// - Inline comments
18	    /// - Multi-level section nesting with dots: [a.b.c]
19	    /// - Empty values (key without value becomes empty string)
20	    pub fn parse(globalThis: *JSGlobalObject, input: []const u8) JSError!JSValue {
21	        const root = JSValue.createEmptyObject(globalThis, 0);
22	        var current_section = root;
23	
24	        var line_iter = LineIterator.init(input);
25	
26	        while (line_iter.next()) |raw_line| {
27	            const line = trimLine(raw_line);
28	
29	            // Skip empty lines and comments
30	            if (line.len == 0) continue;
31	            if (line[0] == ';' or line[0] == '#') continue;
32	
33	            // Section header
34	            if (line[0] == '[') {
35	                current_section = try parseSectionHeader(globalThis, root, line);
36	                continue;
37	            }
38	
39	            // Key-value pair
40	            try parseKeyValue(globalThis, current_section, line);
41	        }
42	
43	        return root;
44	    }
45	
46	    /// Stringify a JSValue into INI format string.
47	    pub fn stringify(globalThis: *JSGlobalObject, value: JSValue) JSError!JSValue {
48	        if (!value.isObject()) {
49	            return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
50	        }
51	
52	        var buf = std.ArrayList(u8).init(bun.default_allocator);
53	        defer buf.deinit();
54	
55	        try stringifyObject(globalThis, value, &buf, null);
56	
57	        var out = bun.String.cloneUTF8(buf.items);
58	        defer out.deref();
59	        return out.toJS(globalThis);
60	    }
61	
62	    fn stringifyObject(globalThis: *JSGlobalObject, value: JSValue, buf: *std.ArrayList(u8), section_prefix: ?[]const u8) JSError!void {
63	        // First pass: write scalar key=value pairs
64	        {
65	            var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
66	                globalThis,
67	                try value.toObject(globalThis),
68	            );
69	            defer iter.deinit();
70	
71	            while (try iter.next()) |prop_name| {
72	                const val = iter.value;
73	                if (val.isObject() and !val.isNull() and !val.isArray()) {
74	                    continue; // Handle nested objects in second pass
75	                }
76	
77	                const key_utf8 = prop_name.toUTF8(bun.default_allocator);
78	                defer key_utf8.deinit();
79	                buf.appendSlice(key_utf8.slice()) catch return error.OutOfMemory;
80	                buf.append('=') catch return error.OutOfMemory;
81	                try appendValue(globalThis, val, buf);
82	                buf.append('\n') catch return error.OutOfMemory;
83	            }
84	        }
85	
86	        // Second pass: write nested objects as sections
87	        {
88	            var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
89	                globalThis,
90	                try value.toObject(globalThis),
91	            );
92	            defer iter.deinit();
93	
94	            while (try iter.next()) |prop_name| {
95	                const val = iter.value;
96	                if (!val.isObject() or val.isNull() or val.isArray()) {
97	                    continue;
98	                }
99	
100	                const key_utf8 = prop_name.toUTF8(bun.default_allocator);
101	                defer key_utf8.deinit();
102	
103	                // Build section name
104	                var section_name = std.ArrayList(u8).init(bun.default_allocator);
105	                defer section_name.deinit();
106	
107	                if (section_prefix) |prefix| {
108	                    section_name.appendSlice(prefix) catch return error.OutOfMemory;
109	                    section_name.append('.') catch return error.OutOfMemory;
110	                }
111	                section_name.appendSlice(key_utf8.slice()) catch return error.OutOfMemory;
112	
113	                // Add blank line before section for readability
114	                if (buf.items.len > 0 and buf.items[buf.items.len - 1] != '\n') {
115	                    buf.append('\n') catch return error.OutOfMemory;
116	                }
117	                if (buf.items.len > 0) {
118	                    buf.append('\n') catch return error.OutOfMemory;
119	                }
120	
121	                buf.append('[') catch return error.OutOfMemory;
122	                buf.appendSlice(section_name.items) catch return error.OutOfMemory;
123	                buf.append(']') catch return error.OutOfMemory;
124	                buf.append('\n') catch return error.OutOfMemory;
125	
126	                try stringifyObject(globalThis, val, buf, section_name.items);
127	            }
128	        }
129	    }
130	
131	    fn appendValue(globalThis: *JSGlobalObject, value: JSValue, buf: *std.ArrayList(u8)) JSError!void {
132	        if (value.isNull() or value.isUndefined()) {
133	            // Write nothing (empty value)
134	            return;
135	        }
136	        if (value.isBoolean()) {
137	            if (value.toBoolean()) {
138	                buf.appendSlice("true") catch return error.OutOfMemory;
139	            } else {
140	                buf.appendSlice("false") catch return error.OutOfMemory;
141	            }
142	            return;
143	        }
144	        if (value.isNumber()) {
145	            if (value.isInt32()) {
146	                var num_buf: [64]u8 = undefined;
147	                const num_str = std.fmt.bufPrint(&num_buf, "{d}", .{value.toInt32()}) catch return;
148	                buf.appendSlice(num_str) catch return error.OutOfMemory;
149	            } else {
150	                var num_buf: [64]u8 = undefined;
151	                const num_str = std.fmt.bufPrint(&num_buf, "{d}", .{value.asNumber()}) catch return;
152	                buf.appendSlice(num_str) catch return error.OutOfMemory;
153	            }
154	            return;
155	        }
156	        if (value.isString()) {
157	            const str = try value.toSlice(globalThis, bun.default_allocator);
158	            defer str.deinit();
159	            buf.appendSlice(str.slice()) catch return error.OutOfMemory;
160	            return;
161	        }
162	        if (value.isArray()) {
163	            // Represent arrays as comma-separated values
164	            const len: u32 = @intCast(try value.getLength(globalThis));
165	            var i: u32 = 0;
166	            while (i < len) : (i += 1) {
167	                if (i > 0) buf.appendSlice(", ") catch return error.OutOfMemory;
168	                const item = try value.getIndex(globalThis, i);
169	                try appendValue(globalThis, item, buf);
170	            }
171	            return;
172	        }
173	        // Fallback: convert to string
174	        const str = try value.toSlice(globalThis, bun.default_allocator);
175	        defer str.deinit();
176	        buf.appendSlice(str.slice()) catch return error.OutOfMemory;
177	    }
178	
179	    fn parseSectionHeader(globalThis: *JSGlobalObject, root: JSValue, line: []const u8) JSError!JSValue {
180	        // Find closing bracket
181	        const close = strings.indexOfChar(line, ']') orelse return root;
182	        if (close <= 1) return root;
183	
184	        const section_name = trimLine(line[1..close]);
185	        if (section_name.len == 0) return root;
186	
187	        // Support dotted sections like [a.b.c]
188	        var current = root;
189	        var name_iter = DotIterator.init(section_name);
190	        while (name_iter.next()) |part| {
191	            const trimmed = trimLine(part);
192	            if (trimmed.len == 0) continue;
193	
194	            const existing = try current.getOwn(globalThis, trimmed);
195	            if (existing) |ex| {
196	                if (ex.isObject() and !ex.isNull()) {
197	                    current = ex;
198	                    continue;
199	                }
200	            }
201	            const new_obj = JSValue.createEmptyObject(globalThis, 0);
202	            current.put(globalThis, &ZigString.init(trimmed), new_obj);
203	            current = new_obj;
204	        }
205	
206	        return current;
207	    }
208	
209	    fn parseKeyValue(globalThis: *JSGlobalObject, section: JSValue, line: []const u8) JSError!void {
210	        // Find separator (= or :)
211	        var sep_idx: ?usize = null;
212	        for (line, 0..) |c, i| {
213	            if (c == '=' or c == ':') {
214	                sep_idx = i;
215	                break;
216	            }
217	        }
218	
219	        const key_end = sep_idx orelse line.len;
220	        const key = trimLine(line[0..key_end]);
221	        if (key.len == 0) return;
222	
223	        const raw_value = if (sep_idx) |idx|
224	            (if (idx + 1 < line.len) trimLine(line[idx + 1 ..]) else "")
225	        else
226	            "";
227	
228	        // Strip inline comments (not inside quotes)
229	        const value_str = stripInlineComment(raw_value);
230	
231	        // Parse the value
232	        const js_value = parseValue(globalThis, value_str);
233	
234	        section.put(globalThis, &ZigString.init(key), js_value);
235	    }
236	
237	    fn parseValue(globalThis: *JSGlobalObject, value: []const u8) JSValue {
238	        if (value.len == 0) {
239	            var s = bun.String.empty;
240	            return s.toJS(globalThis);
241	        }
242	
243	        // Handle quoted strings
244	        if (value.len >= 2) {
245	            if ((value[0] == '"' and value[value.len - 1] == '"') or
246	                (value[0] == '\'' and value[value.len - 1] == '\''))
247	            {
248	                const inner = value[1 .. value.len - 1];
249	                var s = bun.String.cloneUTF8(inner);
250	                defer s.deref();
251	                return s.toJS(globalThis);
252	            }
253	        }
254	
255	        // Handle boolean values
256	        if (strings.eqlComptime(value, "true") or strings.eqlComptime(value, "yes") or strings.eqlComptime(value, "on")) {
257	            return JSValue.true;
258	        }
259	        if (strings.eqlComptime(value, "false") or strings.eqlComptime(value, "no") or strings.eqlComptime(value, "off")) {
260	            return JSValue.false;
261	        }
262	
263	        // Handle null
264	        if (strings.eqlComptime(value, "null") or strings.eqlComptime(value, "none")) {
265	            return JSValue.null;
266	        }
267	
268	        // Try to parse as integer
269	        if (std.fmt.parseInt(i64, value, 10)) |int_val| {
270	            return JSValue.jsNumber(int_val);
271	        } else |_| {}
272	
273	        // Try to parse as float
274	        if (std.fmt.parseFloat(f64, value)) |float_val| {
275	            // Only accept float if the string contains a dot to avoid
276	            // re-interpreting strings that were already tried as integers
277	            if (strings.indexOfChar(value, '.') != null) {
278	                return JSValue.jsNumber(float_val);
279	            }
280	        } else |_| {}
281	
282	        // Return as string
283	        var s = bun.String.cloneUTF8(value);
284	        defer s.deref();
285	        return s.toJS(globalThis);
286	    }
287	
288	    fn stripInlineComment(value: []const u8) []const u8 {
289	        var in_single_quote = false;
290	        var in_double_quote = false;
291	
292	        for (value, 0..) |c, i| {
293	            if (c == '\'' and !in_double_quote) {
294	                in_single_quote = !in_single_quote;
295	            } else if (c == '"' and !in_single_quote) {
296	                in_double_quote = !in_double_quote;
297	            } else if ((c == ';' or c == '#') and !in_single_quote and !in_double_quote) {
298	                return trimLine(value[0..i]);
299	            }
300	        }
301	        return value;
302	    }
303	
304	    fn trimLine(s: []const u8) []const u8 {
305	        return strings.trim(s, " \t\r");
306	    }
307	
308	    const LineIterator = struct {
309	        data: []const u8,
310	        pos: usize,
311	
312	        fn init(data: []const u8) LineIterator {
313	            return .{ .data = data, .pos = 0 };
314	        }
315	
316	        fn next(self: *LineIterator) ?[]const u8 {
317	            if (self.pos >= self.data.len) return null;
318	
319	            const start = self.pos;
320	            while (self.pos < self.data.len and self.data[self.pos] != '\n') {
321	                self.pos += 1;
322	            }
323	            const end = self.pos;
324	            // Skip the newline
325	            if (self.pos < self.data.len) self.pos += 1;
326	
327	            return self.data[start..end];
328	        }
329	    };
330	
331	    const DotIterator = struct {
332	        data: []const u8,
333	        pos: usize,
334	
335	        fn init(data: []const u8) DotIterator {
336	            return .{ .data = data, .pos = 0 };
337	        }
338	
339	        fn next(self: *DotIterator) ?[]const u8 {
340	            if (self.pos >= self.data.len) return null;
341	
342	            const start = self.pos;
343	            while (self.pos < self.data.len and self.data[self.pos] != '.') {
344	                self.pos += 1;
345	            }
346	            const end = self.pos;
347	            // Skip the dot
348	            if (self.pos < self.data.len) self.pos += 1;
349	
350	            return self.data[start..end];
351	        }
352	    };
353	};
