const std = @import("std");
const bun = @import("bun");
const strings = bun.strings;
const jsc = bun.jsc;
const JSValue = jsc.JSValue;
const JSGlobalObject = jsc.JSGlobalObject;
const ZigString = jsc.ZigString;
const JSError = bun.JSError;

pub const INI = struct {
    /// Parse an INI string and return a JSValue representing the parsed object.
    /// Supports:
    /// - [section] headers (creating nested objects)
    /// - key=value and key: value pairs
    /// - Comment lines starting with ; or #
    /// - Quoted string values (single and double quotes)
    /// - Inline comments
    /// - Multi-level section nesting with dots: [a.b.c]
    /// - Empty values (key without value becomes empty string)
    pub fn parse(globalThis: *JSGlobalObject, input: []const u8) JSError!JSValue {
        const root = JSValue.createEmptyObject(globalThis, 0);
        var current_section = root;

        var line_iter = LineIterator.init(input);

        while (line_iter.next()) |raw_line| {
            const line = trimLine(raw_line);

            // Skip empty lines and comments
            if (line.len == 0) continue;
            if (line[0] == ';' or line[0] == '#') continue;

            // Section header
            if (line[0] == '[') {
                current_section = try parseSectionHeader(globalThis, root, line);
                continue;
            }

            // Key-value pair
            try parseKeyValue(globalThis, current_section, line);
        }

        return root;
    }

    /// Stringify a JSValue into INI format string.
    pub fn stringify(globalThis: *JSGlobalObject, value: JSValue) JSError!JSValue {
        if (!value.isObject()) {
            return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
        }

        var buf = std.ArrayList(u8).init(bun.default_allocator);
        defer buf.deinit();

        try stringifyObject(globalThis, value, &buf, null);

        var out = bun.String.cloneUTF8(buf.items);
        defer out.deref();
        return out.toJS(globalThis);
    }

    fn stringifyObject(globalThis: *JSGlobalObject, value: JSValue, buf: *std.ArrayList(u8), section_prefix: ?[]const u8) JSError!void {
        // First pass: write scalar key=value pairs
        {
            var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                globalThis,
                try value.toObject(globalThis),
            );
            defer iter.deinit();

            while (try iter.next()) |prop_name| {
                const val = iter.value;
                if (val.isObject() and !val.isNull() and !val.isArray()) {
                    continue; // Handle nested objects in second pass
                }

                const key_utf8 = prop_name.toUTF8(bun.default_allocator);
                defer key_utf8.deinit();
                buf.appendSlice(key_utf8.slice()) catch return error.OutOfMemory;
                buf.append('=') catch return error.OutOfMemory;
                try appendValue(globalThis, val, buf);
                buf.append('\n') catch return error.OutOfMemory;
            }
        }

        // Second pass: write nested objects as sections
        {
            var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                globalThis,
                try value.toObject(globalThis),
            );
            defer iter.deinit();

            while (try iter.next()) |prop_name| {
                const val = iter.value;
                if (!val.isObject() or val.isNull() or val.isArray()) {
                    continue;
                }

                const key_utf8 = prop_name.toUTF8(bun.default_allocator);
                defer key_utf8.deinit();

                // Build section name
                var section_name = std.ArrayList(u8).init(bun.default_allocator);
                defer section_name.deinit();

                if (section_prefix) |prefix| {
                    section_name.appendSlice(prefix) catch return error.OutOfMemory;
                    section_name.append('.') catch return error.OutOfMemory;
                }
                section_name.appendSlice(key_utf8.slice()) catch return error.OutOfMemory;

                // Add blank line before section for readability
                if (buf.items.len > 0 and buf.items[buf.items.len - 1] != '\n') {
                    buf.append('\n') catch return error.OutOfMemory;
                }
                if (buf.items.len > 0) {
                    buf.append('\n') catch return error.OutOfMemory;
                }

                buf.append('[') catch return error.OutOfMemory;
                buf.appendSlice(section_name.items) catch return error.OutOfMemory;
                buf.append(']') catch return error.OutOfMemory;
                buf.append('\n') catch return error.OutOfMemory;

                try stringifyObject(globalThis, val, buf, section_name.items);
            }
        }
    }

    fn appendValue(globalThis: *JSGlobalObject, value: JSValue, buf: *std.ArrayList(u8)) JSError!void {
        if (value.isNull() or value.isUndefined()) {
            // Write nothing (empty value)
            return;
        }
        if (value.isBoolean()) {
            if (value.toBoolean()) {
                buf.appendSlice("true") catch return error.OutOfMemory;
            } else {
                buf.appendSlice("false") catch return error.OutOfMemory;
            }
            return;
        }
        if (value.isNumber()) {
