                    current = ex;
                    continue;
                }
            }
            const new_obj = JSValue.createEmptyObject(globalThis, 0);
            current.put(globalThis, &ZigString.init(trimmed), new_obj);
            current = new_obj;
        }

        return current;
    }

    fn parseKeyValue(globalThis: *JSGlobalObject, section: JSValue, line: []const u8) JSError!void {
        // Find separator (= or :)
        var sep_idx: ?usize = null;
        for (line, 0..) |c, i| {
            if (c == '=' or c == ':') {
                sep_idx = i;
                break;
            }
        }

        const key_end = sep_idx orelse line.len;
        const key = trimLine(line[0..key_end]);
        if (key.len == 0) return;

        const raw_value = if (sep_idx) |idx|
            (if (idx + 1 < line.len) trimLine(line[idx + 1 ..]) else "")
        else
            "";

        // Strip inline comments (not inside quotes)
        const value_str = stripInlineComment(raw_value);

        // Parse the value
        const js_value = parseValue(globalThis, value_str);

        section.put(globalThis, &ZigString.init(key), js_value);
    }

    fn parseValue(globalThis: *JSGlobalObject, value: []const u8) JSValue {
        if (value.len == 0) {
            var s = bun.String.empty;
            return s.toJS(globalThis);
        }

        // Handle quoted strings
        if (value.len >= 2) {
            if ((value[0] == '"' and value[value.len - 1] == '"') or
                (value[0] == '\'' and value[value.len - 1] == '\''))
            {
                const inner = value[1 .. value.len - 1];
                var s = bun.String.cloneUTF8(inner);
                defer s.deref();
                return s.toJS(globalThis);
            }
        }

        // Handle boolean values
        if (strings.eqlComptime(value, "true") or strings.eqlComptime(value, "yes") or strings.eqlComptime(value, "on")) {
            return JSValue.true;
        }
        if (strings.eqlComptime(value, "false") or strings.eqlComptime(value, "no") or strings.eqlComptime(value, "off")) {
            return JSValue.false;
        }

        // Handle null
        if (strings.eqlComptime(value, "null") or strings.eqlComptime(value, "none")) {
            return JSValue.null;
        }

        // Try to parse as integer
        if (std.fmt.parseInt(i64, value, 10)) |int_val| {
            return JSValue.jsNumber(int_val);
        } else |_| {}

        // Try to parse as float
        if (std.fmt.parseFloat(f64, value)) |float_val| {
            // Only accept float if the string contains a dot to avoid
            // re-interpreting strings that were already tried as integers
            if (strings.indexOfChar(value, '.') != null) {
                return JSValue.jsNumber(float_val);
            }
        } else |_| {}

        // Return as string
        var s = bun.String.cloneUTF8(value);
        defer s.deref();
        return s.toJS(globalThis);
    }

    fn stripInlineComment(value: []const u8) []const u8 {
        var in_single_quote = false;
        var in_double_quote = false;

        for (value, 0..) |c, i| {
            if (c == '\'' and !in_double_quote) {
                in_single_quote = !in_single_quote;
            } else if (c == '"' and !in_single_quote) {
                in_double_quote = !in_double_quote;
            } else if ((c == ';' or c == '#') and !in_single_quote and !in_double_quote) {
                return trimLine(value[0..i]);
            }
        }
        return value;
    }

    fn trimLine(s: []const u8) []const u8 {
        return strings.trim(s, " \t\r");
    }

    const LineIterator = struct {
        data: []const u8,
        pos: usize,

        fn init(data: []const u8) LineIterator {
            return .{ .data = data, .pos = 0 };
        }

        fn next(self: *LineIterator) ?[]const u8 {
            if (self.pos >= self.data.len) return null;

            const start = self.pos;
            while (self.pos < self.data.len and self.data[self.pos] != '\n') {
