                var num_buf: [64]u8 = undefined;
                const num_str = std.fmt.bufPrint(&num_buf, "{d}", .{value.toInt32()}) catch return;
                buf.appendSlice(num_str) catch return error.OutOfMemory;
            } else {
                var num_buf: [64]u8 = undefined;
                const num_str = std.fmt.bufPrint(&num_buf, "{d}", .{value.asNumber()}) catch return;
                buf.appendSlice(num_str) catch return error.OutOfMemory;
            }
            return;
        }
